﻿"use client"

import { useState, type CSSProperties, type ReactNode } from "react"

import { AppSidebar } from "./app-sidebar"
import { SiteHeader } from "../dashboard/site-header"
import { SidebarInset, SidebarProvider } from "@/components/ui/sidebar"
import { TooltipProvider } from "@/components/ui/tooltip"

import { BottomDrawer } from "./bottom-drawer"
import { BottomNav } from "./bottom-nav"

interface DashboardLayoutProps {
  children: ReactNode
}

export function DashboardLayout({ children }: DashboardLayoutProps) {
  const [isDrawerOpen, setIsDrawerOpen] = useState(false)

  return (
    <TooltipProvider>
      <SidebarProvider
        style={
          {
            "--sidebar-width": "15rem",
            "--header-height": "calc(var(--spacing) * 12)",
          } as CSSProperties
        }
        className="h-svh overflow-hidden"
      >
        <AppSidebar variant="sidebar" />
        <SidebarInset className="min-h-svh rounded-none shadow-none">
          <SiteHeader />
          <main className="flex flex-1 flex-col overflow-y-auto overflow-x-hidden pb-20 md:pb-0">
            {children}
          </main>
        </SidebarInset>
        <BottomNav onMoreClick={() => setIsDrawerOpen(true)} />
        <BottomDrawer
          open={isDrawerOpen}
          onClose={() => setIsDrawerOpen(false)}
        />
      </SidebarProvider>
    </TooltipProvider>
  )
}

﻿"use client";

import * as React from "react";
import Link from "next/link";
import { ViewSidebarLeftIcon } from "@hugeicons/core-free-icons";
import { HugeiconsIcon } from "@hugeicons/react";

import {
  Sidebar,
  SidebarContent,
  SidebarFooter,
  SidebarHeader,
  SidebarMenu,
  SidebarMenuButton,
  SidebarMenuItem,
  useSidebar,
} from "@/components/ui/sidebar";
import { cn } from "@/lib/utils";

import {
  dashboardBrand,
  dashboardDocuments,
  dashboardNavMain,
  dashboardNavSecondary,
} from "../dashboard/dashboard-nav-config";
import { NavDocuments } from "./nav-documents";
import { NavMain } from "./nav-main";
import { NavSecondary } from "./nav-secondary";

export function AppSidebar({ ...props }: React.ComponentProps<typeof Sidebar>) {
  const { state, toggleSidebar } = useSidebar();

  return (
    <Sidebar
      collapsible="icon"
      className="h-svh overflow-hidden border-r"
      {...props}
    >
      <SidebarHeader className="border-b">
        <SidebarMenu>
          <SidebarMenuItem>
            <SidebarMenuButton
              asChild
              className="data-[slot=sidebar-menu-button]:p-1.5!"
            >
              <Link href={dashboardBrand.url}>
                <HugeiconsIcon
                  icon={dashboardBrand.icon}
                  size={20}
                  strokeWidth={1.5}
                />
                <span className="text-base font-semibold">
                  {dashboardBrand.title}
                </span>
              </Link>
            </SidebarMenuButton>
          </SidebarMenuItem>
        </SidebarMenu>
      </SidebarHeader>
      <SidebarContent>
        <NavMain items={dashboardNavMain} />
        <NavDocuments items={dashboardDocuments} />
        <NavSecondary items={dashboardNavSecondary} className="mt-auto" />
      </SidebarContent>
      <SidebarFooter>
        <SidebarMenu>
          <SidebarMenuItem>
            <SidebarMenuButton
              onClick={toggleSidebar}
              tooltip={
                state === "collapsed" ? "Expand the menu" : "Collapse the menu"
              }
            >
              <HugeiconsIcon
                icon={ViewSidebarLeftIcon}
                size={20}
                strokeWidth={1.5}
                className={cn(
                  "transition-transform duration-200 ease-in-out",
                  state === "collapsed" && "rotate-180",
                )}
              />
              {state === "collapsed" ? null : <span>Collapse the menu</span>}
            </SidebarMenuButton>
          </SidebarMenuItem>
        </SidebarMenu>
      </SidebarFooter>
    </Sidebar>
  );
}

"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { Menu01Icon } from "@hugeicons/core-free-icons";
import { HugeiconsIcon } from "@hugeicons/react";

import { cn } from "@/lib/utils";
import { dashboardNavMain } from "../dashboard/dashboard-nav-config";

interface BottomNavProps {
  onMoreClick?: () => void;
}

// Les 4 premières icônes de la navigation principale
const navItems = dashboardNavMain.slice(0, 4).map((item) => ({
  href: item.url,
  label: item.title,
  icon: item.icon,
}));

export function BottomNav({ onMoreClick }: BottomNavProps) {
  const pathname = usePathname();

  return (
    <nav className="fixed right-0 bottom-0 left-0 z-50 border-t border-border bg-background md:hidden">
      <div className="grid grid-cols-5">
        {navItems.map((item) => {
          const isActive = pathname === item.href;

          return (
            <Link
              key={item.href}
              href={item.href}
              className={cn(
                "flex flex-col items-center gap-1 px-2 py-2",
                isActive ? "text-primary" : "text-muted-foreground",
              )}
            >
              <HugeiconsIcon icon={item.icon} size={22} strokeWidth={1.5} />
              <span className="text-[10px] truncate w-full text-center">
                {item.label}
              </span>
            </Link>
          );
        })}
        <button
          type="button"
          onClick={onMoreClick}
          className="flex flex-col items-center gap-1 px-2 py-2 text-muted-foreground"
        >
          <HugeiconsIcon icon={Menu01Icon} size={22} strokeWidth={1.5} />
          <span className="text-[10px]">More</span>
        </button>
      </div>
    </nav>
  );
}

