              {dashboardNavMain.map((item) => (
                <DrawerClose asChild key={item.url}>
                  <Link
                    href={item.url}
                    onClick={onClose}
                    className={cn(
                      "flex items-center gap-3 rounded-(--radius) px-3 py-3 text-sm",
                      pathname === item.url
                        ? "bg-primary/10 font-medium text-primary"
                        : "text-muted-foreground hover:bg-accent hover:text-accent-foreground"
                    )}
                  >
                    <HugeiconsIcon
                      icon={item.icon}
                      size={20}
                      strokeWidth={1.5}
                    />
                    <span>{item.title}</span>
                  </Link>
                </DrawerClose>
              ))}
            </section>
            <section className="space-y-1">
              <p className="px-3 text-xs font-medium tracking-wide text-muted-foreground uppercase">
                Documents
              </p>
              {dashboardDocuments.map((item) => (
                <DrawerClose asChild key={item.url}>
                  <Link
                    href={item.url}
                    onClick={onClose}
                    className={cn(
                      "flex items-center gap-3 rounded-(--radius) px-3 py-3 text-sm",
                      pathname === item.url
                        ? "bg-primary/10 font-medium text-primary"
                        : "text-muted-foreground hover:bg-accent hover:text-accent-foreground"
                    )}
                  >
                    <HugeiconsIcon
                      icon={item.icon}
                      size={20}
                      strokeWidth={1.5}
                    />
                    <span>{item.name}</span>
                  </Link>
                </DrawerClose>
              ))}
            </section>
            <section className="space-y-1">
              <p className="px-3 text-xs font-medium tracking-wide text-muted-foreground uppercase">
                Support
              </p>
              {dashboardNavSecondary.map((item) => (
                <DrawerClose asChild key={item.url}>
                  <Link
                    href={item.url}
                    onClick={onClose}
                    className={cn(
                      "flex items-center gap-3 rounded-(--radius) px-3 py-3 text-sm",
                      pathname === item.url
                        ? "bg-primary/10 font-medium text-primary"
                        : "text-muted-foreground hover:bg-accent hover:text-accent-foreground"
                    )}
                  >
                    <HugeiconsIcon
                      icon={item.icon}
                      size={20}
                      strokeWidth={1.5}
                    />
                    <span>{item.title}</span>
                  </Link>
                </DrawerClose>
              ))}
            </section>
            <section className="space-y-1 border-t pt-4">
              <DrawerClose asChild>
                <Link
                  href="/logout"
                  onClick={onClose}
                  className="flex items-center gap-3 rounded-(--radius) px-3 py-3 text-sm text-muted-foreground hover:bg-accent hover:text-accent-foreground"
                >
                  <HugeiconsIcon
                    icon={Logout01Icon}
                    size={20}
                    strokeWidth={1.5}
                  />
                  <span>Log out</span>
                </Link>
