"use client"

import * as React from "react"
import { Moon02Icon, Sun03Icon } from "@hugeicons/core-free-icons"
import { HugeiconsIcon } from "@hugeicons/react"

import { Button } from "@/components/ui/button"

const THEME_STORAGE_KEY = "murgodash-theme"
const RIPPLE_DURATION = 600 // ms

function getPreferredTheme(): "light" | "dark" {
  if (typeof window === "undefined") {
    return "light"
  }

  const storedTheme = window.localStorage.getItem(THEME_STORAGE_KEY)
  if (storedTheme === "light" || storedTheme === "dark") {
    return storedTheme
  }

  return window.matchMedia("(prefers-color-scheme: dark)").matches
    ? "dark"
    : "light"
}

interface RippleState {
  active: boolean
  x: number
  y: number
  /** "expand" = dark→light (vague sortante) | "collapse" = light→dark (vague entrante) */
  direction: "expand" | "collapse"
  /** couleur de l'overlay selon le thème cible */
  color: string
}

export function ThemeToggle() {
  const [theme, setTheme] = React.useState<"light" | "dark">("light")
  const [ripple, setRipple] = React.useState<RippleState>({
    active: false,
    x: 0,
    y: 0,
    direction: "expand",
    color: "#ffffff",
  })
  const buttonRef = React.useRef<HTMLButtonElement>(null)

  const applyTheme = React.useCallback((nextTheme: "light" | "dark") => {
    const root = document.documentElement
    root.classList.toggle("dark", nextTheme === "dark")
    root.style.colorScheme = nextTheme
    window.localStorage.setItem(THEME_STORAGE_KEY, nextTheme)
    setTheme(nextTheme)
  }, [])

  React.useEffect(() => {
    applyTheme(getPreferredTheme())
  }, [applyTheme])

  const toggleTheme = React.useCallback(() => {
    if (ripple.active) return

    const nextTheme = theme === "dark" ? "light" : "dark"
    const prefersReducedMotion = window.matchMedia(
      "(prefers-reduced-motion: reduce)"
    ).matches

    if (prefersReducedMotion) {
      applyTheme(nextTheme)
      return
    }

    // Calculer la position du bouton (centre du bouton en % de la fenêtre)
    let xPct = 50
    let yPct = 50
    if (buttonRef.current) {
      const rect = buttonRef.current.getBoundingClientRect()
      xPct = ((rect.left + rect.width / 2) / window.innerWidth) * 100
      yPct = ((rect.top + rect.height / 2) / window.innerHeight) * 100
    }

    // dark→light : overlay blanc qui s'expande (reveal du clair)
    // light→dark : overlay sombre qui se rétracte vers le bouton (reveal du sombre)
    const direction = nextTheme === "light" ? "expand" : "collapse"
    const overlayColor =
      nextTheme === "light"
        ? "oklch(1 0 0)"   // blanc = thème clair
        : "oklch(0.145 0 0)" // sombre = thème sombre

    setRipple({
      active: true,
      x: xPct,
      y: yPct,
      direction,
      color: overlayColor,
    })

    // Pour "collapse" (light→dark) : on change le thème au début
    // pour que l'overlay sombre semble "absorber" le thème clair
    if (direction === "collapse") {
      applyTheme(nextTheme)
    }

    // Pour "expand" (dark→light) : on change le thème à mi-chemin
    // pour que le nouveau thème soit révélé sous l'overlay
    if (direction === "expand") {
      window.setTimeout(() => {
        applyTheme(nextTheme)
      }, RIPPLE_DURATION * 0.4)
    }

    window.setTimeout(() => {
      setRipple((prev) => ({ ...prev, active: false }))
    }, RIPPLE_DURATION + 50)
  }, [applyTheme, ripple.active, theme])

  const isDark = theme === "dark"

  return (
    <>
      {/* Overlay de ripple circulaire */}
      {ripple.active && (
        <div
          aria-hidden="true"
          className="pointer-events-none fixed inset-0 z-9999"
          style={
            {
              backgroundColor: ripple.color,
              "--ripple-x": `${ripple.x}%`,
              "--ripple-y": `${ripple.y}%`,
              animationName:
                ripple.direction === "expand"
                  ? "theme-ripple-expand"
                  : "theme-ripple-collapse",
              animationDuration: `${RIPPLE_DURATION}ms`,
              animationTimingFunction: "cubic-bezier(0.4, 0, 0.2, 1)",
              animationFillMode: "forwards",
            } as React.CSSProperties
          }
        />
      )}

      {/* Bouton de bascule */}
      <Button
        ref={buttonRef}
        type="button"
        variant="outline"
        size="sm"
        className="h-9 w-9"
        onClick={toggleTheme}
        aria-label={isDark ? "Switch to light theme" : "Switch to dark theme"}
        title={isDark ? "Switch to light theme" : "Switch to dark theme"}
      >
        <HugeiconsIcon
          icon={isDark ? Sun03Icon : Moon02Icon}
          size={20}
          strokeWidth={1.5}
        />
      </Button>
    </>
  )
}

"use client"

import Link from "next/link"
import { usePathname } from "next/navigation"
import type { IconSvgElement } from "@hugeicons/react"
import { HugeiconsIcon } from "@hugeicons/react"

import {
  SidebarGroup,
  SidebarGroupContent,
  SidebarGroupLabel,
  SidebarMenu,
  SidebarMenuButton,
  SidebarMenuItem,
} from "@/components/ui/sidebar"

export function NavMain({
  items,
}: {
  items: {
    title: string
    url: string
    icon?: IconSvgElement
  }[]
}) {
  const pathname = usePathname()

  return (
    <SidebarGroup>
      <SidebarGroupContent>
        <SidebarGroupLabel>Home</SidebarGroupLabel>
        <SidebarMenu>
          {items.map((item) => {
            const isActive = pathname === item.url

            return (
              <SidebarMenuItem key={item.title}>
                <SidebarMenuButton
                  asChild
                  tooltip={item.title}
                  isActive={isActive}
                >
                  <Link href={item.url}>
                    {item.icon ? (
                      <HugeiconsIcon
                        icon={item.icon}
                        size={20}
                        strokeWidth={1.5}
                      />
                    ) : null}
                    <span>{item.title}</span>
                  </Link>
                </SidebarMenuButton>
              </SidebarMenuItem>
            )
          })}
        </SidebarMenu>
      </SidebarGroupContent>
    </SidebarGroup>
  )
}

