    <div className="grid grid-cols-1 gap-4 px-4 lg:px-6 @xl/main:grid-cols-2 @5xl/main:grid-cols-4">
      {sectionCards.map((card) => (
        <SectionCard key={card.description} card={card} />
      ))}
    </div>
  )
}

