export default function LifecyclePage() {
  const [searchValue, setSearchValue] = React.useState("");
  const [filterValues, setFilterValues] = React.useState<
    Record<string, string>
  >({
    status: "",
    urgency: "",
  });

  // Filtres configurables pour le SearchFilter
  const filters: FilterField[] = [
    {
      id: "status",
      label: "Status",
      render: (value, onChange) => (
        <Select value={value} onValueChange={onChange}>
          <SelectTrigger id="sf-filter-status" className="w-full">
            <SelectValue placeholder="Select status" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="Active">Active</SelectItem>
            <SelectItem value="Review">Review</SelectItem>
            <SelectItem value="Draft">Draft</SelectItem>
            <SelectItem value="Pending">Pending</SelectItem>
            <SelectItem value="Abandoned">Abandoned</SelectItem>
          </SelectContent>
        </Select>
      ),
    },
    {
      id: "urgency",
      label: "Urgency",
      render: (value, onChange) => (
        <Select value={value} onValueChange={onChange}>
          <SelectTrigger id="sf-filter-urgency" className="w-full">
            <SelectValue placeholder="Select urgency" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="High">High</SelectItem>
            <SelectItem value="Medium">Medium</SelectItem>
            <SelectItem value="Low">Low</SelectItem>
          </SelectContent>
        </Select>
      ),
    },
  ];

  // Logique de filtrage (search + filters)
  const filteredData = initialData.filter((item) => {
    const matchesSearch =
      item.stage.toLowerCase().includes(searchValue.toLowerCase()) ||
      item.owner.toLowerCase().includes(searchValue.toLowerCase());

    const matchesStatus =
      !filterValues.status || item.status === filterValues.status;
    const matchesUrgency =
      !filterValues.urgency || item.urgency === filterValues.urgency;

    return matchesSearch && matchesStatus && matchesUrgency;
  });

  return (
    <div className="flex flex-col gap-6 py-6 px-4 lg:px-6">
      <div className="flex flex-col gap-1">
        <h1 className="text-2xl font-bold tracking-tight">Lifecycle</h1>
        <p className="text-muted-foreground">
          Manage your project lifecycle stages and track progress.
        </p>
      </div>

      <div className="flex flex-col gap-4">
        {/* Intégration du composant SearchFilter */}
        <div className="flex items-center gap-3">
          <SearchFilter
            placeholder="Filter by stage or owner..."
            searchValue={searchValue}
            onSearchChange={setSearchValue}
            filters={filters}
            filterValues={filterValues}
            onFiltersApply={setFilterValues}
            onFiltersReset={() => setFilterValues({ status: "", urgency: "" })}
            className="w-full max-w-sm"
          />
        </div>

        {/* Tableau des données */}
        <div className="overflow-hidden rounded-lg border">
          <Table>
            <TableHeader className="bg-muted/50">
              <TableRow>
                <TableHead className="w-1/4">Stage</TableHead>
                <TableHead>Status</TableHead>
                <TableHead>Urgency</TableHead>
                <TableHead>Owner</TableHead>
                <TableHead className="text-right">ID</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {filteredData.length > 0 ? (
                filteredData.map((item) => (
                  <TableRow key={item.id}>
                    <TableCell className="font-medium">{item.stage}</TableCell>
                    <TableCell>
                      <Badge
                        variant={
                          item.status === "Abandoned"
                            ? "destructive"
                            : "secondary"
                        }
                        className="rounded-full px-2 py-0"
                      >
                        {item.status}
                      </Badge>
                    </TableCell>
                    <TableCell>{item.urgency}</TableCell>
                    <TableCell>{item.owner}</TableCell>
                    <TableCell className="text-right font-mono text-xs text-muted-foreground">
                      #{item.id}
                    </TableCell>
                  </TableRow>
                ))
              ) : (
                <TableRow>
                  <TableCell
                    colSpan={5}
                    className="h-24 text-center text-muted-foreground"
                  >
                    No results found.
                  </TableCell>
                </TableRow>
              )}
            </TableBody>
          </Table>
        </div>
      </div>
    </div>
  );
}
